import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import toppingsList from '../toppings';

const BASE_PRICE = 30;
const TOPPING_PRICE = 8;

export default function PizzaMenu() {
  const [selectedToppings, setSelectedToppings] = useState([]);
  const navigate = useNavigate();
  const auth = JSON.parse(localStorage.getItem('pizzaAuth') || '{}');
  const cart = JSON.parse(localStorage.getItem('cart') || '{}');

  const toggleTopping = topping =>
    setSelectedToppings(prev =>
      prev.includes(topping) ? prev.filter(t => t !== topping) : [...prev, topping]
    );

  const handleAddToCart = () => {
    localStorage.setItem('cart', JSON.stringify({
      toppings: selectedToppings,
      total: BASE_PRICE + selectedToppings.length * TOPPING_PRICE,
    }));
    navigate('/cart');
  };

  const total = BASE_PRICE + selectedToppings.length * TOPPING_PRICE;

  return (
    <div className="max-w-md mx-auto min-h-screen bg-gray-50 pb-20">

      {/* Navy Header */}
      <div className="bg-navy px-5 pt-5 pb-4 flex items-center justify-between">
        <div>
          <h1 className="text-white text-2xl font-black tracking-tight">פיצה סטורי</h1>
          <p className="text-blue-200 text-xs mt-0.5">אוכל טרי, מהיר ומעולה</p>
        </div>
        <button
          onClick={() => navigate('/cart')}
          className="relative bg-white/15 hover:bg-white/25 text-white w-11 h-11 rounded-full flex items-center justify-center transition"
        >
          <span className="text-xl">🛒</span>
          {cart.toppings && (
            <span
              className="absolute -top-1 -right-1 bg-tomato text-white text-xs font-bold w-5 h-5 rounded-full flex items-center justify-center"
              style={{ fontSize: 9 }}
            >1</span>
          )}
        </button>
      </div>

      {/* Address / Status Bar */}
      <div className="bg-navy/90 px-5 pb-3 flex items-center gap-2">
        <span className="text-white/60 text-sm">📍</span>
        <span className="text-white/80 text-xs flex-1 truncate">
          {auth.verified ? 'רחוב הפיצה 1, תל אביב' : 'הכנסו כדי לשמור כתובת'}
        </span>
        <span className="text-xs bg-green-400/20 text-green-300 px-2 py-0.5 rounded-full font-medium border border-green-400/30">
          ● פתוח
        </span>
      </div>

      <div className="px-4 pt-4 space-y-4">

        {/* Hero Pizza Card */}
        <div className="bg-white rounded-2xl shadow-md overflow-hidden">
          {/* Pizza Image */}
          <div className="relative">
            <img
              src="https://images.unsplash.com/photo-1513104890138-7c749659a591?auto=format&fit=crop&w=500&q=80"
              alt="pizza"
              className="w-full h-52 object-cover"
            />
            <div className="absolute inset-0 bg-gradient-to-t from-black/50 via-transparent to-transparent" />
            <div className="absolute bottom-3 right-3 flex gap-2">
              <span className="bg-white/95 text-gray-700 text-xs font-bold px-2.5 py-1 rounded-full shadow">
                🕐 20–30 דק'
              </span>
              <span className="bg-tomato text-white text-xs font-bold px-2.5 py-1 rounded-full shadow">
                החל מ-{BASE_PRICE}₪
              </span>
            </div>
          </div>

          <div className="p-4">
            <div className="flex justify-between items-start mb-1">
              <h2 className="text-xl font-black text-gray-900">פיצה קלאסית</h2>
              <span className="text-2xl font-black text-tomato">{BASE_PRICE}₪</span>
            </div>
            <p className="text-gray-400 text-sm mb-4">בצק טרי, רוטב עגבניות ביתי, גבינת מוצרלה</p>

            {/* Toppings Section */}
            <div className="mb-4">
              <div className="flex items-center justify-between mb-2.5">
                <span className="font-bold text-gray-800 text-sm">בחר תוספות</span>
                <span className="text-xs text-gray-400 bg-gray-100 px-2 py-1 rounded-full">
                  +{TOPPING_PRICE}₪ לתוספת
                </span>
              </div>
              <div className="flex flex-wrap gap-2">
                {toppingsList.map(topping => {
                  const active = selectedToppings.includes(topping);
                  return (
                    <button
                      key={topping}
                      onClick={() => toggleTopping(topping)}
                      className={`px-3 py-1.5 rounded-xl text-sm font-medium border transition select-none active:scale-95 ${
                        active
                          ? 'bg-tomato text-white border-tomato shadow-sm'
                          : 'bg-gray-50 border-gray-200 text-gray-600 hover:border-tomato/50'
                      }`}
                    >
                      {active ? '✓ ' : ''}{topping}
                    </button>
                  );
                })}
              </div>
            </div>

            {/* Price Summary */}
            {selectedToppings.length > 0 && (
              <div className="bg-gray-50 rounded-xl px-3 py-2 mb-3 flex justify-between items-center">
                <span className="text-sm text-gray-500">
                  פיצה + {selectedToppings.length} תוספות
                </span>
                <span className="font-bold text-gray-800">{total}₪</span>
              </div>
            )}

            {/* Add to Cart CTA */}
            <button
              onClick={handleAddToCart}
              className="w-full bg-tomato text-white rounded-2xl font-black text-lg flex items-center justify-between px-5 py-4 transition active:scale-95 shadow-md hover:bg-red-700"
            >
              <span className="text-3xl font-black leading-none">+</span>
              <span>הוסף לסל</span>
              <span className="bg-white/20 px-3 py-1 rounded-xl text-base font-bold">{total}₪</span>
            </button>
          </div>
        </div>

        {/* Login Prompt Card (if not auth'd) */}
        {!auth.verified && (
          <div
            className="bg-navy rounded-2xl p-4 flex items-center justify-between cursor-pointer active:scale-95 transition"
            onClick={() => navigate('/login')}
          >
            <div>
              <p className="text-white font-bold text-sm">כנסו לחשבון שלכם</p>
              <p className="text-blue-200 text-xs mt-0.5">עקבו אחרי הזמנות ותוכנית נאמנות</p>
            </div>
            <span className="text-2xl">👤</span>
          </div>
        )}

      </div>
    </div>
  );
}
